document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".highlight").forEach(e=>{const n=e.querySelector("pre");if(!n)return;const t=document.createElement("button");t.className="copy-btn",t.type="button",t.innerHTML="复制",e.appendChild(t),t.addEventListener("click",()=>{const e=n.querySelector("code"),s=e?e.innerText:n.innerText;navigator.clipboard.writeText(s).then(()=>{t.innerHTML="已复制!",setTimeout(()=>{t.innerHTML="复制"},2e3)}).catch(e=>{console.error("复制失败: ",e)})})})})